    "    (void)algo_mode;  /* Families G/H: actively used above; no-op for modes 0..4 */\n"
    "    uint M[16];\n"
    "    int total_len = (int)slen + len;\n"
    "    int pos = 0;\n"
    "\n"
    "    /* Process complete 64-byte blocks. Build M[] LITTLE-ENDIAN directly\n"
    "     * from bytes; salt bytes for p < slen, password bytes for p >= slen.\n"
    "     * Per-byte LE position: byte i into word (i >> 2) at shift (i & 3) * 8. */\n"
    "    while (total_len - pos >= HASH_BLOCK_BYTES) {\n"
    "        for (int j = 0; j < 16; j++) M[j] = 0u;\n"
    "        for (int i = 0; i < HASH_BLOCK_BYTES; i++) {\n"
    "            int p = pos + i;\n"
    "            uchar c;\n"
    "            if (p < (int)slen) {\n"
    "                c = salt_buf[p];\n"
    "            } else {\n"
    "                c = data[p - (int)slen];\n"
    "            }\n"
    "            M[i >> 2] |= ((uint)c) << ((i & 3) * 8);\n"
    "        }\n"
    "        rmd160_block(&st->h[0], M);\n"
    "        pos += HASH_BLOCK_BYTES;\n"
    "    }\n"
    "\n"
    "    /* Build final block(s): tail bytes + 0x80 marker + zeros + 64-bit\n"
    "     * LE length. */\n"
    "    int rem = total_len - pos;  /* 0..63 */\n"
    "    for (int j = 0; j < 16; j++) M[j] = 0u;\n"
    "    for (int i = 0; i < rem; i++) {\n"
    "        int p = pos + i;\n"
    "        uchar c;\n"
    "        if (p < (int)slen) {\n"
    "            c = salt_buf[p];\n"
    "        } else {\n"
    "            c = data[p - (int)slen];\n"
    "        }\n"
    "        M[i >> 2] |= ((uint)c) << ((i & 3) * 8);\n"
    "    }\n"
    "    /* 0x80 padding marker, LE byte position. */\n"
    "    M[rem >> 2] |= ((uint)0x80u) << ((rem & 3) * 8);\n"
    "\n"
    "    if (rem < 56) {\n"
    "        /* Length fits in this block. M[14] = low 32 bits of bit count,\n"
    "         * M[15] = high 32 bits (= 0 for total_len < 2^29 bytes). */\n"
    "        M[14] = (uint)((uint)total_len * 8u);\n"
    "        M[15] = 0u;\n"
    "        rmd160_block(&st->h[0], M);\n"
    "    } else {\n"
    "        /* Need one extra padding-only block to hold the length. */\n"
    "        rmd160_block(&st->h[0], M);\n"
    "        for (int j = 0; j < 16; j++) M[j] = 0u;\n"
    "        M[14] = (uint)((uint)total_len * 8u);\n"
    "        M[15] = 0u;\n"
    "        rmd160_block(&st->h[0], M);\n"
    "    }\n"
    "}\n"
    "\n"
    "/* template_iterate: -i loop step. Re-encode the digest as 40-byte\n"
    " * lowercase hex ASCII and rehash with fresh IV. RMD160 hex output is 40\n"
    " * chars (5 words × 8 chars = 40 hex chars) — same width as SHA1 — but\n"
    " * the byte ordering is LE.\n"
    " *\n"
    " * Mirrors gpu_ripemd160_core.cl rev 1.1 lines 218-235 byte-for-byte:\n"
    " *   - 5 LE state words → 10 LE-encoded hex M[] words (2 words per state\n"
    " *     word, 4 hex chars each)\n"
    " *   - M[10] = 0x80 (LE 0x80 padding at byte offset 40)\n"
    " *   - M[11..13] = 0\n"
    " *   - M[14] = 40 * 8 = 320 (low 32 bits of bit count)\n"
    " *   - M[15] = 0\n"
    " *   - state reset to RIPEMD-160 IV; rmd160_block.\n"
    " *\n"
    " * For HMAC-RIPEMD-160 (the production use of this carrier core),\n"
    " * max_iter is forced to 1 host-side, so this iter body is structurally\n"
    " * unreachable in production. Kept for symmetry with the SHA-1 sibling\n"
    " * and for future RIPEMD160SALTPASS support if/when added. */\n"
    "static inline void template_iterate(template_state *st)\n"
    "{\n"
    "    uint M[16];\n"
    "    /* Hex-encode 5 LE state words into M[0..9] (40 hex chars, LE\n"
    "     * packing). hex_byte_lc helper from gpu_common.cl produces a 16-bit\n"
    "     * LE pair (low byte = high hex digit, high byte = low hex digit;\n"
    "     * because we store the result into M[] LE this corresponds to the\n"
    "     * correct ASCII byte order in the message stream). */\n"
    "    for (int i = 0; i < 5; i++) {\n"
    "        uint s = st->h[i];\n"
    "        uint b0 = s & 0xff,        b1 = (s >> 8) & 0xff;\n"
    "        uint b2 = (s >> 16) & 0xff, b3 = (s >> 24) & 0xff;\n"
    "        M[i*2]     = hex_byte_lc(b0) | (hex_byte_lc(b1) << 16);\n"
    "        M[i*2 + 1] = hex_byte_lc(b2) | (hex_byte_lc(b3) << 16);\n"
    "    }\n"
    "    M[10] = 0x80u;                   /* LE 0x80 at byte offset 40 */\n"
    "    for (int j = 11; j < 14; j++) M[j] = 0u;\n"
    "    M[14] = 40u * 8u;                /* 40 hex chars = 320 bits */\n"
    "    M[15] = 0u;\n"
    "    /* Reinitialize state to RIPEMD-160 IV; absorb the prepared M[]. */\n"
    "    st->h[0] = 0x67452301u;\n"
    "    st->h[1] = 0xEFCDAB89u;\n"
    "    st->h[2] = 0x98BADCFEu;\n"
    "    st->h[3] = 0x10325476u;\n"
    "    st->h[4] = 0xC3D2E1F0u;\n"
    "    rmd160_block(&st->h[0], M);\n"
    "}\n"
    "\n"
    "/* template_digest_compare: probe the compact table with the final digest.\n"
    " * RMD160 state is LE-native — pass h[0..3] DIRECTLY (no bswap32). The\n"
    " * 5th state word is NOT used by the compact-table probe — only by\n"
    " * EMIT_HIT_5 below. Mirrors gpu_ripemd160_core.cl rev 1.1 lines 257-265. */\n"
    "static inline int template_digest_compare(\n"
    "    const template_state *st,\n"
    "    __global const uint *compact_fp, __global const uint *compact_idx,\n"
    "    ulong compact_mask, uint max_probe, uint hash_data_count,\n"
    "    __global const uchar *hash_data_buf, __global const ulong *hash_data_off,\n"
    "    __global const ulong *overflow_keys, __global const uchar *overflow_hashes,\n"
    "    __global const uint *overflow_offsets, uint overflow_count,\n"
    "    uint *out_idx)\n"
    "{\n"
    "    return probe_compact_idx(\n"
    "        st->h[0], st->h[1], st->h[2], st->h[3],\n"
    "        compact_fp, compact_idx,\n"
    "        compact_mask, max_probe, hash_data_count,\n"
    "        hash_data_buf, hash_data_off,\n"
    "        overflow_keys, overflow_hashes, overflow_offsets, overflow_count,\n"
    "        out_idx);\n"
    "}\n"
    "\n"
    "/* template_emit_hit: emit a hit into the global hits buffer. Wraps\n"
    " * EMIT_HIT_5. Hits buffer convention matches gpu_ripemd160_core.cl /\n"
    " * gpu_rmd160unsalted.cl: 5 LE state words DIRECTLY (no bswap32). */\n"
    "#define template_emit_hit(hits, hit_count, max_hits, st, widx, sidx, iter) \\\n"
    "    EMIT_HIT_5((hits), (hit_count), (max_hits), \\\n"
    "               (widx), (sidx), (iter), ((st)->h))\n"
    "\n"
    "/* B3 dedup+overflow-aware variant. See gpu_ripemd160_core.cl for protocol\n"
    " * notes. */\n"
    "#define template_emit_hit_or_overflow(hits, hit_count, max_hits, st, widx, sidx, iter, \\\n"
    "                                      hashes_shown, matched_idx, dedup_mask, \\\n"
    "                                      ovr_set, ovr_gid, lane_gid) \\\n"
    "    EMIT_HIT_5_DEDUP_OR_OVERFLOW((hits), (hit_count), (max_hits), \\\n"
    "               (widx), (sidx), (iter), ((st)->h), \\\n"
    "               (hashes_shown), (matched_idx), (dedup_mask), \\\n"
    "               (ovr_set), (ovr_gid), (lane_gid))\n"
;
